function normalizePlatform(p) {
  const v = String(p || '').toLowerCase().trim();
  if (v === 'web') return 'website';
  return v || 'website';
}

const BLOCKED_DOMAINS = [
  'eventim.',
  'ticketmaster.',
  'getgo.',
  'reservix.',
  'adticket.',
  'tickets.',
  'koelnticket.',
  'eventfrog.',
  'rausgegangen.'
];

const DETAIL_PATH_HINTS = [
  '/event/',
  '/veranstaltung/',
  '/etkinlik/',
  '/programm/',
  '/program/'
];

const LISTING_PATH_HINTS = [
  '/calendar',
  '/kalender',
  '/events',
  '/veranstaltungen',
  '/termine',
  '/program',
  '/programm',
  '/tag/',
  '/category/',
  '/kategorie/'
];

function normalizeUrl(rawUrl) {
  let u = String(rawUrl || '').trim();
  if (!u) return null;

  if (!/^https?:\/\//i.test(u)) {
    u = 'https://' + u;
  }

  try {
    const parsed = new URL(u);
    parsed.hash = '';
    const host = parsed.hostname.replace(/^www\./i, '');
    const path = parsed.pathname || '/';
    return `${parsed.protocol}//${host}${path}`;
  } catch {
    return u;
  }
}

function getUrlMeta(rawUrl) {
  try {
    const parsed = new URL(rawUrl);
    const host = parsed.hostname.replace(/^www\./i, '').toLowerCase();
    const path = (parsed.pathname || '/').toLowerCase();
    const segments = path.split('/').filter(Boolean);
    const blockedDomain = BLOCKED_DOMAINS.some(domain => host.includes(domain));
    const isHome = path === '/' || path === '';
    const detailish = DETAIL_PATH_HINTS.some(hint => path.includes(hint)) || segments.some(segment => segment.length >= 24 && segment.includes('-'));
    const listingish = LISTING_PATH_HINTS.some(hint => path === hint || path.startsWith(`${hint}/`) || path.includes(`${hint}?`) || path.includes(hint));

    return {
      host,
      path,
      blockedDomain,
      isHome,
      detailish,
      listingish,
    };
  } catch {
    return {
      host: null,
      path: null,
      blockedDomain: false,
      isHome: false,
      detailish: false,
      listingish: false,
    };
  }
}

const originalUrl = $json.url || null;
const normalizedUrl = normalizeUrl(originalUrl);
const urlMeta = normalizedUrl ? getUrlMeta(normalizedUrl) : getUrlMeta('');

return {
  json: {
    ...$json,
    platform: normalizePlatform($json.platform),
    original_url: originalUrl,
    fetch_url: normalizedUrl,
    url: normalizedUrl,
    source_host: urlMeta.host,
    source_path: urlMeta.path,
    blocked_domain: urlMeta.blockedDomain,
    path_is_home: urlMeta.isHome,
    path_is_detailish: urlMeta.detailish,
    path_is_listingish: urlMeta.listingish,
  }
};

function stripHtml(html) {
  return String(html || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<!--.*?-->/gs, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function getTitle(html) {
  const m = String(html || '').match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  return m ? m[1].replace(/\s+/g, ' ').trim() : null;
}

function getMetaContent(html, pattern) {
  const m = String(html || '').match(pattern);
  return m ? String(m[1] || '').trim() : null;
}

function hasJsonLdEvent(html) {
  return /"@type"\s*:\s*"Event"|"@type"\s*:\s*\[\s*"Event"/i.test(String(html || ''));
}

function hasOgEvent(html) {
  return /<meta[^>]+property=["']og:type["'][^>]+content=["']event["']/i.test(String(html || ''));
}

function detectLanguage(text) {
  const t = (text || '').toLowerCase();
  if (/[çğıöşü]/.test(t) || / turkce | türkçe | etkinlik | konser | bilet | dernek | vakif | cami /.test(` ${t} `)) {
    return 'tr';
  }
  return 'de';
}

function guessEntity(text) {
  const t = (text || '').toLowerCase();
  if (/event|veranstaltung|konzert|festival|party|tickets|bilet|etkinlik|gece|iftar|meeting|meetup/.test(t)) {
    return 'EVENT';
  }
  return 'UNKNOWN';
}

function looksGenericTitle(title) {
  const t = String(title || '').toLowerCase().trim();
  if (!t) return true;
  return (
    /^home /.test(t) ||
    /^events? $/.test(t) ||
    /^veranstaltungen $/.test(t) ||
    /^termine $/.test(t) ||
    /^calendar /.test(t) ||
    /^programm $/.test(t) ||
    /^program $/.test(t) ||
    /^tickets? /.test(t) ||
    /^discover /.test(t)
  );
}

function hasDateSignal(text) {
  const t = String(text || '');
  return (
    / \d{1,2}[./-]\d{1,2}([./-]\d{4})? /.test(t) ||
    / \d{4}-\d{2}-\d{2} /.test(t) ||
    / (januar|februar|märz|maerz|april|mai|juni|juli|august|september|oktober|november|dezember|january|february|march|april|may|june|july|august|september|october|november|december) /i.test(t)
  );
}

function hasVenueSignal(text) {
  return /halle|saal|zentrum|center|kultur|moschee|cami|hotel|arena|theater|cafe|restaurant|gemeinde|haus|salon|stage|club|venue|ort |location /i.test(String(text || ''));
}

function hasCommunitySignal(text) {
  return /turk|türk|anatol|iftar|ramadan|ramazan|dernek|vakif|vakf|cami|moschee|konzert|etkinlik|buluşma|bulusma|community|kultur/i.test(String(text || '').toLowerCase());
}

const item = $json;
const statusCode = Number(item.statusCode || 0);

let html = '';
if (typeof item.body === 'string') {
  html = item.body;
} else if (typeof item.data === 'string') {
  html = item.data;
} else if (item.data && typeof item.data.body === 'string') {
  html = item.data.body;
}

let errorMessage = null;

const rawError = item.error ? String(item.error.message || item.error || '') : '';
const combinedError = `${rawError} ${html}`;

if (item.blocked_domain) {
  errorMessage = 'BLOCKED_DOMAIN';
} else if (/ENOTFOUND/i.test(rawError)) {
  errorMessage = 'DNS_NOT_FOUND';
} else if (/EPROTO|SSL/i.test(rawError)) {
  errorMessage = 'SSL_HANDSHAKE_FAILED';
} else if (/timeout/i.test(rawError)) {
  errorMessage = 'TIMEOUT';
} else if (statusCode >= 400) {
  errorMessage = `HTTP_${statusCode}`;
} else if (!html || html.length < 50) {
  errorMessage = 'EMPTY_OR_TOO_SHORT_RESPONSE';
} else if (/captcha|access denied|forbidden|please enable cookies|temporarily unavailable|login|anmelden|einloggen/i.test(combinedError)) {
  errorMessage = 'BLOCKED_OR_LOGIN_WALL';
}

const rawTitle = getTitle(html) || item.name || item.fetch_url || item.url || 'Unknown Source';
const rawText = stripHtml(html).slice(0, 12000);
const normalizedSourceUrl = typeof item.fetch_url === 'string' ? item.fetch_url : (typeof item.url === 'string' ? item.url : null);

if (!errorMessage && !normalizedSourceUrl) {
  errorMessage = 'MISSING_SOURCE_URL';
}

const jsonLdEvent = hasJsonLdEvent(html);
const ogEvent = hasOgEvent(html);
const dateSignal = hasDateSignal(`${rawTitle} ${rawText}`);
const venueSignal = hasVenueSignal(rawText);
const communitySignal = hasCommunitySignal(`${rawTitle} ${rawText}`);
const citySignal = / berlin | koeln | koln | cologne /i.test(`${rawTitle} ${rawText} ${normalizedSourceUrl || ''}`);
const usefulSignalCount = [jsonLdEvent, ogEvent, dateSignal, venueSignal, communitySignal, citySignal].filter(Boolean).length;
const tooLittleText = rawText.length < 350;
const genericTitle = looksGenericTitle(rawTitle);
const weakListingPage = Boolean(item.path_is_listingish) && !item.path_is_detailish && usefulSignalCount < 2;
const weakHomePage = Boolean(item.path_is_home) && usefulSignalCount < 2;
const weakContent = tooLittleText && usefulSignalCount < 2;

if (!errorMessage && genericTitle && usefulSignalCount < 2) {
  errorMessage = 'GENERIC_TITLE';
} else if (!errorMessage && weakListingPage) {
  errorMessage = 'LISTING_PAGE';
} else if (!errorMessage && weakHomePage) {
  errorMessage = 'HOME_PAGE';
} else if (!errorMessage && weakContent) {
  errorMessage = 'WEAK_CONTENT';
}

const status = errorMessage ? 'ERROR' : 'PENDING';

const payload = {
  source: {
    id: item.id,
    platform: item.platform,
    source_kind: item.source_kind,
    name: item.name,
    url: item.url,
    original_url: item.original_url || null,
    fetch_url: item.fetch_url || item.url || null,
    account_handle: item.account_handle,
    external_id: item.external_id,
    trust_score: item.trust_score,
    host: item.source_host || null,
    path: item.source_path || null,
  },
  fetch_meta: {
    statusCode: statusCode || null,
    headers: item.headers || null,
    error: rawError || null
  },
  fetched_at: new Date().toISOString(),
  title: rawTitle,
  text_excerpt_length: rawText.length,
  quality_signals: {
    jsonLdEvent,
    ogEvent,
    dateSignal,
    venueSignal,
    communitySignal,
    citySignal,
    usefulSignalCount,
    pathIsDetailish: Boolean(item.path_is_detailish),
    pathIsListingish: Boolean(item.path_is_listingish),
    pathIsHome: Boolean(item.path_is_home),
  }
};

return {
  json: {
    source_id: item.id || null,
    platform: item.platform || 'website',
    source_url: normalizedSourceUrl,
    external_id: item.external_id || null,
    raw_title: rawTitle,
    raw_text: rawText || null,
    raw_datetime_text: null,
    raw_location_text: null,
    raw_image_url: null,
    raw_payload_json: JSON.stringify(payload),
    language_hint: detectLanguage(`${rawTitle} ${rawText}`),
    city_guess: null,
    country_code: 'DE',
    entity_guess: guessEntity(`${rawTitle} ${rawText}`),
    status,
    error_message: errorMessage
  }
};

const items = $input.all();

const POSITIVE_KEYWORDS = [
  'veranstaltung',
  'veranstaltungen',
  'event',
  'events',
  'termin',
  'termine',
  'kalender',
  'programm',
  'seminar',
  'workshop',
  'konferenz'
];

const HARD_NEGATIVE_KEYWORDS = [
  'impressum',
  'datenschutz',
  'privacy',
  'kontakt',
  'contact',
  'spende',
  'donation',
  'login'
];

const FALLBACK_PATHS = [
  '/veranstaltungen',
  '/veranstaltungen/',
  '/events',
  '/events/',
  '/termine',
  '/termine/',
  '/kalender',
  '/kalender/',
  '/programm',
  '/programm/'
];

const anchorRegex = new RegExp('<a\\\\b([^>]*)href=["\\\']([^"\\\']+)["\\\']([^>]*)>([\\\\s\\\\S]*?)<\\\\/a>', 'gi');
const ariaLabelRegex = new RegExp("aria-label=[\"\\\\']([^\"\\\\']+)[\"\\\\']", 'i');
const tagRegex = new RegExp('<[^>]+>', 'g');
const whitespaceRegex = new RegExp('\\s+', 'g');
const dateTextRegex = new RegExp('\\b\\d{1,2}[./-]\\d{1,2}(?:[./-]\\d{2,4})?\\b');
const eventTextRegex = new RegExp('\\b(event|veranstaltung|veranstaltungen|termin|termine|seminar|workshop|konferenz)\\b');

function normalizeUrl(href, baseUrl) {
  try {
    const value = String(href || '').trim();
    if (!value) return null;
    if (/^(#|mailto:|tel:|javascript:)/i.test(value)) return null;
    const url = new URL(value, baseUrl);
    url.hash = '';
    return url.toString();
  } catch {
    return null;
  }
}

function getSourceId(source) {
  return source?.source_id ?? source?.id ?? source?.sourceId ?? null;
}

function getSourceName(source) {
  return source?.source_name ?? source?.name ?? null;
}

function getSourceUrl(source) {
  return source?.source_url ?? source?.url ?? source?.fetch_url ?? null;
}

function getStatusCode(source) {
  return Number(source?.statusCode ?? source?.status_code ?? source?.httpStatus ?? 0);
}

function getHtml(source) {
  if (typeof source?.data === 'string') return source.data;
  if (typeof source?.body === 'string') return source.body;
  if (source?.data && typeof source.data.body === 'string') return source.data.body;
  return null;
}

function extractError(source) {
  if (!source?.error) return null;

  if (typeof source.error === 'string') {
    return {
      code: String(source.errorCode ?? source.code ?? 'fetch_error'),
      message: source.error,
    };
  }

  if (typeof source.error === 'object') {
    return {
      code: String(source.error.code ?? source.errorCode ?? source.code ?? 'fetch_error'),
      message: String(source.error.message ?? source.errorMessage ?? 'Fetch failed'),
    };
  }

  return {
    code: String(source.errorCode ?? source.code ?? 'fetch_error'),
    message: 'Fetch failed',
  };
}

function decodeEntities(text) {
  return String(text || '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&#8211;|&#x2013;/gi, '–');
}

function extractAnchorLabel(beforeHref, afterHref, innerHtml, href) {
  const openingTag = `${beforeHref || ''} ${afterHref || ''}`;
  const ariaMatch = String(openingTag).match(ariaLabelRegex);
  if (ariaMatch?.[1]) return decodeEntities(ariaMatch[1]).trim();

  const text = decodeEntities(innerHtml)
    .replace(tagRegex, ' ')
    .replace(whitespaceRegex, ' ')
    .trim();

  return text || href;
}

function scoreCandidate(url, label) {
  const haystack = `${String(url || '').toLowerCase()} ${String(label || '').toLowerCase()}`;
  const positiveKeywords = POSITIVE_KEYWORDS.filter((keyword) => haystack.includes(keyword));
  const negativeKeywords = HARD_NEGATIVE_KEYWORDS.filter((keyword) => haystack.includes(keyword));
  const reasons = [];
  let score = 0;

  if (positiveKeywords.length > 0) {
    score += positiveKeywords.length * 3;
    reasons.push(`positive:${positiveKeywords.join(',')}`);
  }

  if (negativeKeywords.length > 0) {
    score -= negativeKeywords.length * 5;
    reasons.push(`hard_negative:${negativeKeywords.join(',')}`);
  }

  if (dateTextRegex.test(String(label || ''))) {
    score += 1;
    reasons.push('date_text');
  }

  if (eventTextRegex.test(String(label || '').toLowerCase())) {
    score += 2;
    reasons.push('event_text');
  }

  return {
    score,
    positiveKeywords,
    negativeKeywords,
    reasons,
  };
}

function addFallbackCandidates(sourceUrl, seen, eventLinks, debugLinks) {
  for (const path of FALLBACK_PATHS) {
    const absoluteUrl = normalizeUrl(path, sourceUrl);
    if (!absoluteUrl || seen.has(absoluteUrl)) continue;
    seen.add(absoluteUrl);

    eventLinks.push({
      url: absoluteUrl,
      label: 'fallback',
      score: 0,
      source: 'generated',
    });

    debugLinks.push({
      url: absoluteUrl,
      label: 'fallback',
      accepted: true,
      score: 0,
      positive_keywords: [],
      negative_keywords: [],
      reasons: ['fallback_generated'],
      reason: 'fallback_generated',
    });
  }
}

function classifyLinks(html, sourceUrl) {
  const seen = new Set();
  const eventLinks = [];
  const nonEventCandidates = [];
  const debugLinks = [];
  let match;

  while ((match = anchorRegex.exec(String(html || ''))) !== null) {
    const href = String(match[2] || '').trim();
    const absoluteUrl = normalizeUrl(href, sourceUrl);
    if (!absoluteUrl || seen.has(absoluteUrl)) continue;
    seen.add(absoluteUrl);

    const label = extractAnchorLabel(match[1], match[3], match[4], href);
    const { score, positiveKeywords, negativeKeywords, reasons } = scoreCandidate(absoluteUrl, label);
    const accepted = positiveKeywords.length > 0 && negativeKeywords.length === 0 && score >= 3;

    const debugEntry = {
      url: absoluteUrl,
      label,
      accepted,
      score,
      positive_keywords: positiveKeywords,
      negative_keywords: negativeKeywords,
      reasons,
    };
    debugLinks.push(debugEntry);

    const candidate = {
      label,
      url: absoluteUrl,
      score,
      positive_keywords: positiveKeywords,
      negative_keywords: negativeKeywords,
      reasons,
    };

    if (accepted) {
      eventLinks.push(candidate);
    } else if (positiveKeywords.length > 0 || negativeKeywords.length > 0) {
      nonEventCandidates.push(candidate);
    }
  }

  if (eventLinks.length === 0) {
    addFallbackCandidates(sourceUrl, seen, eventLinks, debugLinks);
  }

  return { eventLinks, nonEventCandidates, debugLinks };
}

return items.map((item) => {
  const source = item.json || {};
  const sourceId = getSourceId(source);
  const sourceName = getSourceName(source);
  const sourceUrl = getSourceUrl(source);
  const statusCode = getStatusCode(source);
  const html = getHtml(source);
  const fetchError = extractError(source);
  const isSuccess = Number.isFinite(statusCode) && statusCode >= 200 && statusCode < 300;

  if (!isSuccess || typeof html !== 'string' || fetchError) {
    const error = fetchError ?? {
      code: !isSuccess ? `http_${statusCode || 'unknown'}` : 'no_html',
      message: !isSuccess ? `Fetch failed with status ${statusCode || 'unknown'}` : 'No HTML payload available',
    };

    return {
      json: {
        source_id: sourceId,
        source_name: sourceName,
        source_url: sourceUrl,
        status: 'fetch_error',
        event_links: [],
        non_event_candidates: [],
        debug_links: [],
        errors: [error],
      },
    };
  }

  const { eventLinks, nonEventCandidates, debugLinks } = classifyLinks(html, sourceUrl);

  return {
    json: {
      source_id: sourceId,
      source_name: sourceName,
      source_url: sourceUrl,
      status: 'ok',
      event_links: eventLinks,
      non_event_candidates: nonEventCandidates,
      debug_links: debugLinks,
      errors: [],
    },
  };
});

const items = $input.all();
const output = [];

for (const item of items) {
  const source = item.json || {};
  const sourceUrl = typeof source.source_url === 'string' ? source.source_url : null;
  const sourceName = source.source_name ?? null;
  const sourceId = source.source_id ?? null;
  const eventLinks = Array.isArray(source.event_links) ? source.event_links : [];

  for (const candidate of eventLinks) {
    const candidateUrl = typeof candidate?.url === 'string' ? candidate.url : null;
    if (!candidateUrl) continue;

    output.push({
      json: {
        source_id: sourceId,
        source_name: sourceName,
        source_url: sourceUrl,
        original_fetch_url: sourceUrl,
        fetch_url: candidateUrl,
        candidate_anchor_text: candidate?.label ?? null,
        candidate_score: candidate?.score ?? null,
        candidate_reasons: Array.isArray(candidate?.reasons) ? candidate.reasons : [],
      },
    });
  }
}

return output;
